[BusinessEvents(classStr(SalesInvoiceBusinessEventContract), "SalesInvoiceGenerated", "Fires when a Sales Order Invoice is posted", ModuleAxapta::SalesOrder)]
public final class SalesInvoiceBusinessEvent extends BusinessEventsBase
{
    private CustInvoiceJour invoiceJour;

}

Method.Source:
private CustInvoiceJour parmInvoiceJour(CustInvoiceJour _invoiceJour = invoiceJour)
{
    invoiceJour = _invoiceJour;
    return invoiceJour;
}

public static SalesInvoiceBusinessEvent newFromCustInvoiceJour(CustInvoiceJour _invoiceJour)
{
    SalesInvoiceBusinessEvent businessEvent = new SalesInvoiceBusinessEvent();
    businessEvent.parmInvoiceJour(_invoiceJour);
    return businessEvent;
}
